import React, { useState, useEffect } from 'react';
import axios from 'axios';

const Categories = () => {
  const [categories, setCategories] = useState([]);

  useEffect(() => {
    fetchCategories();
  }, []);

  const fetchCategories = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/categories');
      setCategories(res.data);
    } catch (err) {
      console.error('Error fetching categories:', err);
    }
  };

  return (
    <div style={{ padding: '20px', maxWidth: '1200px', margin: '0 auto' }}>
      <h1 style={{ color: '#4a148c', textAlign: 'center', marginBottom: '30px' }}>Book Categories</h1>
      <p style={{ textAlign: 'center', color: '#6a1b9a', marginBottom: '40px' }}>
        Discover books organized by categories. Find your favorite genre and explore new interests.
      </p>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))', gap: '20px' }}>
        {categories.length > 0 ? (
          categories.map(category => (
            <div key={category._id} style={{
              backgroundColor: 'white',
              borderRadius: '10px',
              padding: '20px',
              boxShadow: '0 4px 8px rgba(0,0,0,0.1)',
              border: '1px solid #e1bee7',
              textAlign: 'center'
            }}>
              <h3 style={{ color: '#4a148c', marginBottom: '10px' }}>{category.name}</h3>
              <p style={{ color: '#6a1b9a' }}>{category.description || 'Explore books in this fascinating category.'}</p>
            </div>
          ))
        ) : (
          <p style={{ textAlign: 'center', color: '#6a1b9a', gridColumn: '1 / -1' }}>No categories available at the moment.</p>
        )}
      </div>
    </div>
  );
};

export default Categories;
